{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "title": "Interaction Log",
  "description": "Log of a learner interaction with SAGE",
  "type": "object",
  "properties": {
    "id": { "type": "string", "format": "uuid" },
    "userId": { "type": "string" },
    "sessionId": { "type": "string" },
    "timestamp": { "type": "string", "format": "date-time" },
    "skillUsed": { "type": "string" },
    "practiceType": {
      "type": "string",
      "enum": ["prompt_crafting", "output_evaluation", "appropriateness_judgment", "workflow_design", null],
      "description": "Type of practice session (null if not a practice session)"
    },
    "scenarioId": { "type": "string" },
    "turns": {
      "type": "array",
      "items": {
        "type": "object",
        "properties": {
          "role": { "type": "string", "enum": ["sage", "learner", "simulated_agent"] },
          "content": { "type": "string" },
          "timestamp": { "type": "string", "format": "date-time" },
          "metadata": {
            "type": "object",
            "properties": {
              "skillTransition": { "type": "string" },
              "scoreEvent": { "type": "object" },
              "simulationMode": { "type": "string", "enum": ["helpful_agent", "flawed_agent", "lab_mode"] },
              "scaffoldingStep": { "type": "string", "enum": ["acknowledge", "nudge", "explain", null] }
            }
          }
        },
        "required": ["role", "content"]
      }
    },
    "scaffoldingSteps": {
      "type": "array",
      "description": "Tracking of ACKNOWLEDGE → NUDGE → EXPLAIN steps during feedback",
      "items": {
        "type": "object",
        "properties": {
          "turnIndex": { "type": "integer", "description": "Index of the turn where scaffolding occurred" },
          "step": { "type": "string", "enum": ["acknowledge", "nudge", "explain"] },
          "content": { "type": "string" },
          "learnerRespondedToNudge": { "type": "boolean" }
        }
      }
    },
    "closingReflection": {
      "type": "object",
